fix:
private int matchRecordTypeConstraint(RhinoClassType prototype) throws ScriptException {
  List<String> missingProperties = new ArrayList<>();
  boolean allPresentAndMatching = true;

  for (Map.Entry<PropertyKey, JSType> entry : prototype.getOwnPropertyTypes().entrySet()) {
    PropertyKey key = entry.getKey();
    if (!hasKey(key)) {
      missingProperties.add(key.toString());
    } else {
      JSType value = getKey(key).getStaticValue();
      if (value != null && !getPropertyValue(key).matchesPattern(value)) {
        throw new RhinoException("actual parameter " + currentFunctionParameterIndex
                + " of " + currentFunctionName + " does not match formal parameter");
      }
    }
  }
  return (allPresentAndMatching ? MatchResult.PERFECT_MATCH : MatchResult.PARTIAL_MATCH);
}

